import { Feature, Geometry } from 'geojson';

/**
 * 서버에서 반환하는 공간 분석 결과 데이터 구조
 */
export interface SpatialAnalysisResult {
  file_id: string;
  total_features: number;
  total_area_m2: number;
  total_area_py: number;
  bbox: [number, number, number, number]; // [minX, minY, maxX, maxY]
  metadata: Record<string, any>;
}

/**
 * 지도 레이어의 메타데이터 및 상태 정보
 */
export interface LayerInfo {
  id: string;
  name: string;
  visible: boolean;
  data: any; // GeoJSON 데이터
  analysis?: SpatialAnalysisResult;
}

/**
 * GeoJSON Feature 타입 확장
 */
export type GeoJSONFeature = Feature<Geometry, Record<string, any>>;

import { create } from 'zustand';
import { LayerInfo } from '../types/spatial';

interface MapState {
  zoom: number;
  center: [number, number];
  layers: LayerInfo[];
}

interface MapActions {
  setZoom: (zoom: number) => void;
  setCenter: (center: [number, number]) => void;
  addLayer: (layer: LayerInfo) => void;
  removeLayer: (id: string) => void;
  toggleLayerVisibility: (id: string) => void;
}

/**
 * 지도 관련 전역 상태를 관리하는 Zustand 스토어
 */
export const useMapStore = create<MapState & MapActions>((set) => ({
  zoom: 13,
  center: [37.5665, 126.9780], // 서울 중심좌표
  layers: [],

  setZoom: (zoom) => set({ zoom }),
  setCenter: (center) => set({ center }),

  addLayer: (layer) => set((state) => ({
    layers: [...state.layers, layer]
  })),

  removeLayer: (id) => set((state) => ({
    layers: state.layers.filter((l) => l.id !== id)
  })),

  toggleLayerVisibility: (id) => set((state) => ({
    layers: state.layers.map((l) => 
      l.id === id ? { ...l, visible: !l.visible } : l
    )
  })),
}));

import { create } from 'zustand';
import { GeoJSONFeature } from '../types/spatial';

interface FeatureState {
  selectedFeature: GeoJSONFeature | null;
  hoveredFeature: GeoJSONFeature | null;
}

interface FeatureActions {
  setSelectedFeature: (feature: GeoJSONFeature | null) => void;
  setHoveredFeature: (feature: GeoJSONFeature | null) => void;
  clearSelection: () => void;
}

/**
 * 선택된 지리 객체와 해당 속성을 관리하는 Zustand 스토어
 */
export const useFeatureStore = create<FeatureState & FeatureActions>((set) => ({
  selectedFeature: null,
  hoveredFeature: null,

  setSelectedFeature: (feature) => set({ selectedFeature: feature }),
  setHoveredFeature: (feature) => set({ hoveredFeature: feature }),
  clearSelection: () => set({ selectedFeature: null, hoveredFeature: null }),
}));

import { useMutation } from '@tanstack/react-query';
import { SpatialAnalysisResult } from '../../types/spatial';

/**
 * GeoJSON 파일 업로드 및 분석 결과 수신을 위한 커스텀 훅
 */
export const useUploadGeoJson = () => {
  return useMutation<SpatialAnalysisResult, Error, File>({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('file', file);

      const response = await fetch('/api/v1/geojson/upload', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('파일 업로드에 실패했습니다.');
      }

      return response.json();
    },
  });
};

import { useQuery } from '@tanstack/react-query';
import { SpatialAnalysisResult } from '../../types/spatial';

/**
 * 특정 파일의 공간 분석 상세 정보를 조회하는 커스텀 훅
 */
export const useGetSpatialAnalysis = (fileId: string | null) => {
  return useQuery<SpatialAnalysisResult, Error>({
    queryKey: ['spatialAnalysis', fileId],
    queryFn: async () => {
      if (!fileId) throw new Error('파일 ID가 필요합니다.');

      const response = await fetch(`/api/v1/geojson/${fileId}`);

      if (!response.ok) {
        throw new Error('분석 데이터를 불러오는데 실패했습니다.');
      }

      return response.json();
    },
    enabled: !!fileId,
  });
};

import React from 'react';

interface LoadingOverlayProps {
  isVisible: boolean;
  message?: string;
}

/**
 * 비동기 작업 중 사용자의 상호작용을 제어하고 진행 상태를 알리는 오버레이 컴포넌트
 */
const LoadingOverlay: React.FC<LoadingOverlayProps> = ({ isVisible, message = '데이터를 처리 중입니다...' }) => {
  if (!isVisible) return null;

  return (
    <div style={{
      position: 'fixed',
      top: 0, left: 0, right: 0, bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex', flexDirection: 'column',
      justifyContent: 'center', alignItems: 'center',
      zIndex: 9999,
      color: 'white'
    }}>
      <div className="spinner" style={{
        border: '4px solid rgba(255, 255, 255, 0.3)',
        borderTop: '4px solid #ffffff',
        borderRadius: '50%',
        width: '40px',
        height: '40px',
        animation: 'spin 1s linear infinite',
        marginBottom: '10px'
      }} />
      <p>{message}</p>
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default React.memo(LoadingOverlay);

import React from 'react';

interface AnalysisCardProps {
  label: string;
  value: number;
  unit?: string;
}

/**
 * 특정 폴리곤의 면적 정보 등 분석 수치를 시각적으로 강조하는 카드 컴포넌트
 */
const AnalysisCard: React.FC<AnalysisCardProps> = ({ label, value, unit = '㎡' }) => {
  return (
    <div style={{
      padding: '16px',
      backgroundColor: '#f8f9fa',
      borderRadius: '8px',
      border: '1px solid #dee2e6',
      marginBottom: '12px'
    }}>
      <div style={{ fontSize: '14px', color: '#6c757d', marginBottom: '4px' }}>
        {label}
      </div>
      <div style={{ fontSize: '20px', fontWeight: 'bold', color: '#212529' }}>
        {value.toLocaleString()} <span style={{ fontSize: '14px', fontWeight: 'normal' }}>{unit}</span>
      </div>
    </div>
  );
};

export default React.memo(AnalysisCard);

import React from 'react';
import { useFeatureStore } from '../../../stores/featureStore';

/**
 * 선택된 지리 객체의 속성 정보를 표 형식으로 시각화하는 패널
 */
const PropertyInspector: React.FC = () => {
  const { selectedFeature, clearSelection } = useFeatureStore();

  if (!selectedFeature) return null;

  const properties = selectedFeature.properties || {};

  return (
    <div style={{
      position: 'absolute',
      right: '20px',
      bottom: '20px',
      width: '320px',
      maxHeight: '400px',
      backgroundColor: 'white',
      boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
      borderRadius: '8px',
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
      zIndex: 1000
    }}>
      <div style={{
        padding: '12px 16px',
        borderBottom: '1px solid #eee',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        backgroundColor: '#f8f9fa'
      }}>
        <h3 style={{ margin: 0, fontSize: '16px' }}>객체 속성 정보</h3>
        <button 
          onClick={clearSelection}
          style={{ border: 'none', background: 'none', cursor: 'pointer', fontSize: '18px' }}
        >
          &times;
        </button>
      </div>
      <div style={{ overflowY: 'auto', padding: '0 16px' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '13px' }}>
          <tbody>
            {Object.entries(properties).map(([key, value]) => (
              <tr key={key} style={{ borderBottom: '1px solid #f0f0f0' }}>
                <td style={{ padding: '8px 0', fontWeight: '600', color: '#666', width: '40%' }}>{key}</td>
                <td style={{ padding: '8px 0', color: '#333', wordBreak: 'break-all' }}>{String(value)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default React.memo(PropertyInspector);

import React from 'react';
import { useMapStore } from '../../../stores/mapStore';
import AnalysisCard from '../../analysis/components/AnalysisCard';

/**
 * 활성 레이어 관리 및 공간 분석 결과 요약을 보여주는 사이드바 컴포넌트
 */
const LayerSidebar: React.FC = () => {
  const { layers, toggleLayerVisibility, removeLayer } = useMapStore();

  return (
    <div style={{
      width: '300px',
      height: '100%',
      backgroundColor: 'white',
      borderRight: '1px solid #ddd',
      padding: '20px',
      display: 'flex',
      flexDirection: 'column',
      zIndex: 1001
    }}>
      <h2 style={{ fontSize: '20px', marginBottom: '20px' }}>레이어 목록</h2>

      <div style={{ flex: 1, overflowY: 'auto' }}>
        {layers.length === 0 ? (
          <p style={{ color: '#999', textAlign: 'center' }}>업로드된 레이어가 없습니다.</p>
        ) : (
          layers.map((layer) => (
            <div key={layer.id} style={{ 
              marginBottom: '20px', 
              padding: '12px', 
              border: '1px solid #eee', 
              borderRadius: '8px'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
                <span style={{ fontWeight: '600' }}>{layer.name}</span>
                <div>
                  <input 
                    type="checkbox" 
                    checked={layer.visible} 
                    onChange={() => toggleLayerVisibility(layer.id)} 
                  />
                  <button 
                    onClick={() => removeLayer(layer.id)}
                    style={{ marginLeft: '8px', color: 'red', border: 'none', background: 'none', cursor: 'pointer' }}
                  >
                    삭제
                  </button>
                </div>
              </div>

              {layer.analysis && (
                <div style={{ marginTop: '10px' }}>
                  <AnalysisCard label="전체 면적" value={layer.analysis.total_area_m2} unit="㎡" />
                  <AnalysisCard label="전체 면적 (평)" value={layer.analysis.total_area_py} unit="평" />
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default React.memo(LayerSidebar);

import React, { useCallback, useRef } from 'react';
import { useUploadGeoJson } from '../../../hooks/mutations/useUploadGeoJson';
import { useMapStore } from '../../../stores/mapStore';

/**
 * GeoJSON 파일 드래그 앤 드롭 업로드 인터페이스 컴포넌트
 */
const FileUploader: React.FC = () => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { mutate, isPending } = useUploadGeoJson();
  const { addLayer } = useMapStore();

  const handleUpload = useCallback((file: File) => {
    mutate(file, {
      onSuccess: (data) => {
        // 업로드 성공 시 로컬에서 파일 읽기 (지도시각화용)
        const reader = new FileReader();
        reader.onload = (e) => {
          const geoJsonData = JSON.parse(e.target?.result as string);
          addLayer({
            id: data.file_id,
            name: file.name,
            visible: true,
            data: geoJsonData,
            analysis: data
          });
        };
        reader.readAsText(file);
      },
      onError: (error) => {
        alert(`업로드 실패: ${error.message}`);
      }
    });
  }, [mutate, addLayer]);

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleUpload(e.target.files[0]);
    }
  };

  return (
    <div 
      onClick={() => fileInputRef.current?.click()}
      style={{
        padding: '20px',
        border: '2px dashed #007bff',
        borderRadius: '8px',
        textAlign: 'center',
        cursor: 'pointer',
        backgroundColor: isPending ? '#f0f0f0' : 'transparent',
        transition: 'background-color 0.2s'
      }}
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={onFileChange} 
        style={{ display: 'none' }} 
        accept=".json,.geojson"
      />
      <div style={{ fontSize: '16px', fontWeight: '500', color: '#007bff' }}>
        {isPending ? '파일 분석 중...' : 'GeoJSON 파일을 여기에 드래그하거나 클릭하여 업로드하세요.'}
      </div>
      <div style={{ fontSize: '12px', color: '#6c757d', marginTop: '8px' }}>
        최대 50MB까지 지원합니다.
      </div>
    </div>
  );
};

export default React.memo(FileUploader);

import React, { useEffect, useRef, useCallback } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { useMapStore } from '../../../stores/mapStore';
import { useFeatureStore } from '../../../stores/featureStore';

/**
 * Leaflet 기반의 핵심 지도 컴포넌트
 */
const MapContainer: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const leafletMap = useRef<L.Map | null>(null);
  const layersGroup = useRef<L.FeatureGroup>(L.featureGroup());

  const { zoom, center, layers, setZoom, setCenter } = useMapStore();
  const { setSelectedFeature } = useFeatureStore();

  // 지도 초기화
  useEffect(() => {
    if (!mapRef.current || leafletMap.current) return;

    leafletMap.current = L.map(mapRef.current).setView(center, zoom);

    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; OpenStreetMap contributors'
    }).addTo(leafletMap.current);

    layersGroup.current.addTo(leafletMap.current);

    leafletMap.current.on('zoomend', () => {
      setZoom(leafletMap.current!.getZoom());
    });

    leafletMap.current.on('moveend', () => {
      const c = leafletMap.current!.getCenter();
      setCenter([c.lat, c.lng]);
    });

    return () => {
      leafletMap.current?.remove();
      leafletMap.current = null;
    };
  }, []);

  // 레이어 렌더링
  useEffect(() => {
    if (!leafletMap.current) return;

    layersGroup.current.clearLayers();

    layers.forEach((layer) => {
      if (!layer.visible) return;

      const geoJsonLayer = L.geoJSON(layer.data, {
        onEachFeature: (feature, leafletLayer) => {
          leafletLayer.on('click', (e) => {
            L.DomEvent.stopPropagation(e);
            setSelectedFeature(feature as any);
          });
        },
        style: {
          color: '#007bff',
          weight: 2,
          fillOpacity: 0.3
        }
      });

      layersGroup.current.addLayer(geoJsonLayer);

      // 새 레이어 추가 시 영역 자동 조정
      if (layers.length > 0 && layer === layers[layers.length - 1]) {
        leafletMap.current?.fitBounds(layersGroup.current.getBounds());
      }
    });
  }, [layers, setSelectedFeature]);

  return (
    <div 
      ref={mapRef} 
      style={{ width: '100%', height: '100%', position: 'relative', zIndex: 1 }}
    />
  );
};

export default React.memo(MapContainer);

import React from 'react';
import MapContainer from '../features/map/components/MapContainer';
import FileUploader from '../features/upload/components/FileUploader';
import LayerSidebar from '../features/sidebar/components/LayerSidebar';
import PropertyInspector from '../features/inspector/components/PropertyInspector';
import LoadingOverlay from '../components/common/LoadingOverlay';
import { useUploadGeoJson } from '../hooks/mutations/useUploadGeoJson';

/**
 * 애플리케이션의 메인 뷰어 레이아웃을 구성하고 상태를 조율하는 페이지 컴포넌트
 */
const MainViewerPage: React.FC = () => {
  const { isPending: isUploading } = useUploadGeoJson();

  return (
    <div style={{
      display: 'flex',
      width: '100vw',
      height: '100vh',
      overflow: 'hidden',
      fontFamily: 'sans-serif'
    }}>
      <LayerSidebar />

      <main style={{ flex: 1, position: 'relative' }}>
        <div style={{
          position: 'absolute',
          top: '20px',
          left: '20px',
          zIndex: 1000,
          width: '400px'
        }}>
          <FileUploader />
        </div>

        <MapContainer />
        <PropertyInspector />
      </main>

      <LoadingOverlay isVisible={isUploading} message="GeoJSON 파일을 분석 중입니다..." />
    </div>
  );
};

export default MainViewerPage;

import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MainViewerPage from '../pages/MainViewerPage';

/**
 * React Router를 사용하여 경로와 페이지를 매핑하는 컴포넌트
 */
const AppRoutes: React.FC = () => {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<MainViewerPage />} />
        {/* 향후 추가 경로 정의 가능 */}
      </Routes>
    </Router>
  );
};

export default AppRoutes;
